function setActiveOptions(){let e=localStorage.security||"Base64",t=document.querySelector('dropmenu[data-type="security"]'),l=t.querySelector("input");t.querySelector(".value").textContent=e,l.value=e;for(let l=0;l<t.querySelectorAll(".op-list li").length;l++)t.querySelectorAll(".op-list li")[l].textContent.match(e)&&t.querySelectorAll(".op-list li")[l].classList.add("active")}setActiveOptions();